-- الدفعة الأولى من ملء محتوى تصنيفات "تعلّم" الفارغة (status='draft')
-- تحت "الحديث والسنة" (hadith-sunnah) — تستنفد العنقود بالكامل (15 تصنيفاً
-- فرعياً بلا محتوى من أصل 19: مدخل إلى السنة، حجية السنة، جوامع الكلم،
-- أحاديث الآداب، أحاديث الترغيب والترهيب، الصحيحان، السنن الأربع، الموطأ،
-- المسند، التخريج، دراسة الأسانيد، العلل، مختلف الحديث ومشكله، غريب
-- الحديث، فقه الحديث). الأربعة الباقية (الأربعون النووية، أحاديث الأحكام،
-- شروح الأحاديث، الدفاع عن السنة) كانت منشورة مسبقاً.
-- كل تصنيف يحصل على درس واحد حقيقي (lessons + lesson_sections +
-- lesson_citations)، مبني على مصادر معتمدة مسمّاة: كتب مصطلح حديث
-- وعلوم حديث كلاسيكية (نزهة النظر لابن حجر، الرسالة للشافعي، فتح الباري
-- لابن حجر، رياض الصالحين للنووي، الترغيب والترهيب للمنذري، مقدمة ابن
-- الصلاح، تدريب الراوي للسيوطي، التمهيد لابن عبد البر، الباعث الحثيث
-- لابن كثير، أصول التخريج ودراسات الأسانيد للطحان، الكفاية في علم
-- الرواية للخطيب البغدادي، علل الحديث لابن أبي حاتم، تأويل مختلف
-- الحديث لابن قتيبة، النهاية في غريب الحديث لابن الأثير، سبل السلام
-- للصنعاني).
-- كل آية استُشهد بها (النساء:80/82، الحشر:7، الحجرات:6، التوبة:122،
-- الأحزاب:21، النجم:3-4، الإسراء:36، البقرة:42، يوسف:2) تحقَّقت حرفياً
-- من public/data/quran محلياً عبر حقل numberInSurah قبل الإدراج (بعضها
-- معاد استخدامه من دفعات سابقة لأنها الآيات المؤسِّسة نفسها لنفس
-- الموضوع، وهذا مقبول). كل حديث مستشهَد به (5 أحاديث) متحقَّق حرفياً
-- عبر WebSearch قبل الإدراج، وكلها من الصحيحين أو متفق عليه أو مروي في
-- الترمذي بتصحيح ثابت غير متذبذب: «بعثت بجوامع الكلم» (البخاري 2977)،
-- «من كان يؤمن بالله واليوم الآخر فليقل خيراً أو ليصمت» (متفق عليه)،
-- «من دل على خير فله مثل أجر فاعله» (مسلم 1893)، «من كذب علي متعمداً
-- فليتبوأ مقعده من النار» (متفق عليه، البخاري 6197 ومسلم 2134)، «نضر
-- الله امرأً سمع مقالتي» (الترمذي 2658، قال: حسن صحيح).
-- idempotent (حارس NOT EXISTS بالعنوان+التصنيف) ثم status='published'
-- للتصنيفات الخمسة عشر عند اكتمالها.
DO $$
DECLARE
  v_lesson uuid;
BEGIN
  -- 1) مدخل إلى السنة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='19915507-0474-47c7-bc61-d4c837adfd19' AND title='تعريف السنة وعلاقتها بالوحي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف السنة وعلاقتها بالوحي', 'معنى السنة لغة واصطلاحاً ومكانتها بوصفها وحياً ثانياً مع القرآن', '19915507-0474-47c7-bc61-d4c837adfd19', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها ومكانتها', 'السنة لغة: الطريقة المتبعة، واصطلاحاً عند المحدثين: كل ما أُثر عن النبي صلى الله عليه وسلم من قول أو فعل أو تقرير أو صفة خَلقية أو خُلقية. وهي عند الأصوليين مصدر تشريع مستقل يبيّن القرآن ويفصّل مجمله ويقيّد مطلقه، فلا يستقل فهم الدين بالقرآن وحده دون الرجوع إلى بيان النبي صلى الله عليه وسلم لمراد الله فيه.', 1),
    (v_lesson, 'evidence', 'أصل ربط طاعته بطاعة الله', 'قال تعالى: ﴿مَنْ يُطِعِ الرَّسُولَ فَقَدْ أَطَاعَ اللَّهَ وَمَنْ تَوَلَّى فَمَا أَرْسَلْنَاكَ عَلَيْهِمْ حَفِيظًا﴾ (النساء: 80)، فربطت الآية طاعة الرسول صلى الله عليه وسلم بطاعة الله تعالى، وهذا أصل مكانة السنة بوصفها بياناً موحى به لا اجتهاداً شخصياً من عند النبي صلى الله عليه وسلم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'نزهة النظر في توضيح نخبة الفكر — الحافظ ابن حجر العسقلاني', 1);
  END IF;

  -- 2) حجية السنة
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='61932eef-1d4b-4417-a34b-3f02bae2c877' AND title='أدلة حجية السنة كمصدر تشريع مستقل') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أدلة حجية السنة كمصدر تشريع مستقل', 'الأدلة القرآنية والعقلية على وجوب الأخذ بالسنة النبوية في التشريع', '61932eef-1d4b-4417-a34b-3f02bae2c877', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'معناها وإجماع الأمة عليها', 'حجية السنة تعني وجوب الاحتجاج بها والعمل بمقتضاها في استنباط الأحكام الشرعية على نحو ما يُحتج بالقرآن، سواء كانت السنة مؤكِّدة لحكم القرآن أو مبيّنة لمجمله أو منشئة لحكم سكت عنه القرآن. وقد أجمعت الأمة على هذا الأصل، ولم يخالف فيه إلا طوائف منكرة معدودة لا اعتبار لخلافها.', 1),
    (v_lesson, 'evidence', 'أصلها من القرآن', 'قال تعالى: ﴿وَمَا آتَاكُمُ الرَّسُولُ فَخُذُوهُ وَمَا نَهَاكُمْ عَنْهُ فَانْتَهُوا﴾ (الحشر: 7)، فهذا أمر عام مطلق بالأخذ بكل ما جاء به الرسول صلى الله عليه وسلم من قول أو فعل، وهو من أصرح أدلة القرآن على وجوب الاحتجاج بالسنة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الرسالة — الإمام محمد بن إدريس الشافعي', 1);
  END IF;

  -- 3) جوامع الكلم
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d315d779-0539-4aed-a961-69c671f8e54a' AND title='خصائص جوامع الكلم النبوية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('خصائص جوامع الكلم النبوية', 'تعريف جوامع الكلم وأثرها في بلاغة الحديث النبوي وإيجازه', 'd315d779-0539-4aed-a961-69c671f8e54a', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها وأثرها', 'جوامع الكلم عبارات قليلة الألفاظ واسعة المعاني والمقاصد اختص الله بها نبيه صلى الله عليه وسلم، فيجمع اللفظ الواحد منها أصولاً كلية وقواعد عامة تتفرع عنها أحكام كثيرة، وهي من أبرز أوجه الإعجاز البياني في الحديث النبوي، وقد اعتنى العلماء بجمع هذا النوع من الأحاديث وشرح ما فيه من معانٍ جامعة كالأحاديث الأربعين النووية.', 1),
    (v_lesson, 'evidence', 'أصل المصطلح من الحديث نفسه', 'عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «بُعِثْتُ بِجَوَامِعِ الْكَلِمِ وَنُصِرْتُ بِالرُّعْبِ» رواه البخاري، وهذا الحديث هو الأصل الذي استمد منه علماء الحديث مصطلح جوامع الكلم ذاته.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'فتح الباري بشرح صحيح البخاري — الحافظ ابن حجر العسقلاني', 1);
  END IF;

  -- 4) أحاديث الآداب
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='4ce9831f-2300-43bf-ad94-822f593b054f' AND title='منزلة أحاديث الآداب في السنة النبوية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منزلة أحاديث الآداب في السنة النبوية', 'تعريف علم أحاديث الآداب وأثره في تهذيب سلوك المسلم اليومي', '4ce9831f-2300-43bf-ad94-822f593b054f', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها ومجالها', 'أحاديث الآداب هي الأحاديث النبوية المنظمة لسلوك المسلم في تعامله مع نفسه وأسرته وجيرانه ومجتمعه، كآداب الطعام والشراب والمجلس والزيارة وحسن الجوار وحفظ اللسان، وقد أفرد المحدثون لهذا الباب مصنفات مستقلة لضخامة الأحاديث الواردة فيه وشدة الحاجة إليها في تقويم السلوك اليومي.', 1),
    (v_lesson, 'evidence', 'حديث جامع في الآداب', 'عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيَقُلْ خَيْرًا أَوْ لِيَصْمُتْ، وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ جَارَهُ، وَمَنْ كَانَ يُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ فَلْيُكْرِمْ ضَيْفَهُ» متفق عليه، وهو من أجمع الأحاديث في باب الآداب لجمعه بين أدب اللسان وأدب الجوار وأدب الضيافة.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'رياض الصالحين — الإمام يحيى بن شرف النووي', 1);
  END IF;

  -- 5) أحاديث الترغيب والترهيب
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='2e680f74-9d31-4218-8e22-7e9c4cf63283' AND title='منهج التصنيف في أحاديث الترغيب والترهيب') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منهج التصنيف في أحاديث الترغيب والترهيب', 'تعريف هذا الفن الحديثي وأثره في الترغيب بالطاعات والترهيب من المعاصي', '2e680f74-9d31-4218-8e22-7e9c4cf63283', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه والغرض منه', 'أحاديث الترغيب والترهيب هي الأحاديث الواردة في بيان ثواب الطاعات وفضلها وعقاب المعاصي وسوء عاقبتها، بقصد تحريك القلب نحو الخير وتحذيره من الشر، وقد أفرد لها المحدثون مصنفات جامعة تُعنى بجمعها من الكتب المسندة وبيان درجتها، تيسيراً على العامة والخاصة للانتفاع بها في الوعظ والتذكير.', 1),
    (v_lesson, 'evidence', 'مثال على أحاديث الترغيب', 'عن أبي مسعود عقبة بن عمرو الأنصاري رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَنْ دَلَّ عَلَى خَيْرٍ فَلَهُ مِثْلُ أَجْرِ فَاعِلِهِ» رواه مسلم، وهذا من أظهر أحاديث الترغيب لما فيه من حث على الدلالة على الخير بوعد الأجر العظيم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الترغيب والترهيب من الحديث الشريف — الحافظ عبد العظيم المنذري', 1);
  END IF;

  -- 6) الصحيحان
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='27958e70-ef37-4055-afb2-ea053f44b945' AND title='مكانة الصحيحين وشرط الشيخين في القبول') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('مكانة الصحيحين وشرط الشيخين في القبول', 'تعريف بصحيح البخاري وصحيح مسلم ومنزلتهما بين كتب الحديث', '27958e70-ef37-4055-afb2-ea053f44b945', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفهما ومنزلتهما', 'الصحيحان هما صحيح البخاري وصحيح مسلم، وهما أصح كتابين صُنِّفا في الحديث بعد كتاب الله عند جمهور أهل العلم، لالتزام مصنفيهما بأعلى شروط القبول في اتصال السند وعدالة الرواة وضبطهم وانتفاء الشذوذ والعلة، ويُعرف قبول أهل العلم لحديث ما وصف بأنه (متفق عليه) إذا اتفق الشيخان معاً على إخراجه في صحيحيهما.', 1),
    (v_lesson, 'evidence', 'أصل الاحتياط في نقل كلامه', 'قال تعالى: ﴿وَمَا يَنْطِقُ عَنِ الْهَوَى إِنْ هُوَ إِلَّا وَحْيٌ يُوحَى﴾ (النجم: 3-4)، وهذا الأصل القرآني في عصمة كلام النبي صلى الله عليه وسلم عن الهوى هو الدافع الذي حمل الإمامين البخاري ومسلم على الاحتياط الشديد في انتقاء ما يُنسب إليه صلى الله عليه وسلم في صحيحيهما.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'مقدمة ابن الصلاح (معرفة أنواع علم الحديث) — الإمام أبو عمرو بن الصلاح', 1);
  END IF;

  -- 7) السنن الأربع
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='36310eca-1dcc-4f1d-8348-2ca48c3974d0' AND title='تعريف بالسنن الأربع ومنهجها في الترتيب الفقهي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف بالسنن الأربع ومنهجها في الترتيب الفقهي', 'التعريف بسنن أبي داود والترمذي والنسائي وابن ماجه ومنهجها في جمع أحاديث الأحكام', '36310eca-1dcc-4f1d-8348-2ca48c3974d0', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفها ومنهجها', 'السنن الأربع هي سنن أبي داود السجستاني، وجامع الترمذي، وسنن النسائي، وسنن ابن ماجه، وتشترك في ترتيب أحاديثها على أبواب الفقه لتيسير استخراج الأحكام منها، وتتفاوت في شرط القبول عن الصحيحين، فتضم إلى جانب الصحيح أحاديث حسنة وضعيفة مع بيان مصنفيها غالباً لدرجة ما أوردوه.', 1),
    (v_lesson, 'evidence', 'أصل التخصص الفقهي', 'قال تعالى: ﴿فَلَوْلَا نَفَرَ مِنْ كُلِّ فِرْقَةٍ مِنْهُمْ طَائِفَةٌ لِيَتَفَقَّهُوا فِي الدِّينِ﴾ (التوبة: 122)، وهذا الأصل في التخصص الفقهي هو ما تحقق عملياً في السنن الأربع بترتيبها الحديث على أبواب الفقه لخدمة طلاب العلم المتفقهين في الأحكام.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تدريب الراوي في شرح تقريب النواوي — الإمام جلال الدين السيوطي', 1);
  END IF;

  -- 8) الموطأ
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='efbd98b3-5702-4df2-8fd9-385f63c89dc1' AND title='موطأ الإمام مالك وريادته في الجمع بين الحديث والفقه') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('موطأ الإمام مالك وريادته في الجمع بين الحديث والفقه', 'تعريف بموطأ الإمام مالك بن أنس ومكانته بوصفه من أقدم مصنفات الحديث', 'efbd98b3-5702-4df2-8fd9-385f63c89dc1', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه ومنزلته', 'الموطأ للإمام مالك بن أنس من أقدم المصنفات الجامعة بين الحديث المرفوع وأقوال الصحابة والتابعين وفتاوى أهل المدينة، رتبه مصنفه على أبواب الفقه، وقد بلغ من عناية العلماء به أن وصفه بعضهم بأنه أول كتاب صحيح جُمع في الإسلام قبل تدوين الصحيحين، لالتزام الإمام مالك فيه بمنهج أهل المدينة في التوثق من الرواية.', 1),
    (v_lesson, 'evidence', 'أصل الاقتداء العملي بالسنة', 'قال تعالى: ﴿لَقَدْ كَانَ لَكُمْ فِي رَسُولِ اللَّهِ أُسْوَةٌ حَسَنَةٌ لِمَنْ كَانَ يَرْجُو اللَّهَ وَالْيَوْمَ الْآخِرَ﴾ (الأحزاب: 21)، وهذا الأصل في الاقتداء الفعلي بهدي النبي صلى الله عليه وسلم هو ما جمعه الإمام مالك في موطئه من عمل أهل المدينة المتصل بسنة النبي صلى الله عليه وسلم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'التمهيد لما في الموطأ من المعاني والأسانيد — الحافظ ابن عبد البر', 1);
  END IF;

  -- 9) المسند
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='57df4c60-9374-4f2a-95d5-c368d526a498' AND title='منهج كتب المسانيد وأثر مسند الإمام أحمد') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منهج كتب المسانيد وأثر مسند الإمام أحمد', 'تعريف علم المسانيد ومنهج ترتيبها على أسماء الصحابة رواة الحديث', '57df4c60-9374-4f2a-95d5-c368d526a498', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه ومثاله الأشهر', 'المسند نوع من التصنيف الحديثي يجمع فيه المصنف أحاديث كل صحابي على حدة تحت اسمه بصرف النظر عن موضوعها الفقهي، بخلاف الكتب المرتبة على الأبواب، وأشهر كتب هذا النوع مسند الإمام أحمد بن حنبل الذي جمع فيه نحو ثلاثين ألف حديث مسندة إلى أكثر من تسعمائة صحابي، وقد اعتنى العلماء بضبط نسبة كل حديث إلى راويه من الصحابة توثقاً من صحة الإسناد إلى النبي صلى الله عليه وسلم.', 1),
    (v_lesson, 'evidence', 'دافع دقة النسبة إلى الصحابي', 'عن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «مَنْ كَذَبَ عَلَيَّ مُتَعَمِّدًا فَلْيَتَبَوَّأْ مَقْعَدَهُ مِنَ النَّارِ» متفق عليه، وهذا التحذير الشديد هو الدافع الذي حمل مصنفي المسانيد على نسبة كل حديث بدقة إلى صحابيه الراوي توثقاً من صحة نسبته إلى النبي صلى الله عليه وسلم.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الباعث الحثيث شرح اختصار علوم الحديث — الحافظ ابن كثير', 1);
  END IF;

  -- 10) التخريج
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='164c4d1f-5d2a-483f-8078-d0ceeeafd1be' AND title='تعريف علم التخريج ومناهجه في الوصول إلى مصادر الحديث') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف علم التخريج ومناهجه في الوصول إلى مصادر الحديث', 'تعريف علم تخريج الحديث وأبرز طرقه للوصول إلى الحديث في مصادره الأصلية', '164c4d1f-5d2a-483f-8078-d0ceeeafd1be', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وطرقه', 'التخريج هو الدلالة على موضع الحديث في مصادره الأصلية مع بيان درجته من الصحة أو الضعف، ويعتمد الباحث فيه على طرق عدة كالتخريج بمعرفة الراوي الأعلى، أو بأول لفظ من الحديث عبر المعاجم اللفظية، أو بموضوعه عبر الكتب المرتبة على الأبواب، وهو علم لا غنى عنه لكل باحث أو واعظ يريد التثبت من نسبة حديث ما إلى مصدره قبل الاستشهاد به.', 1),
    (v_lesson, 'evidence', 'أصل النهي عن القول بلا علم', 'قال تعالى: ﴿وَلَا تَقْفُ مَا لَيْسَ لَكَ بِهِ عِلْمٌ إِنَّ السَّمْعَ وَالْبَصَرَ وَالْفُؤَادَ كُلُّ أُولَٰئِكَ كَانَ عَنْهُ مَسْئُولًا﴾ (الإسراء: 36)، فهذا الأصل القرآني في النهي عن القول بلا علم هو ما يقوم عليه علم التخريج من وجوب التثبت من مصدر كل حديث قبل نسبته إلى النبي صلى الله عليه وسلم أو الاستشهاد به.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'أصول التخريج ودراسات الأسانيد — د. محمود الطحان', 1);
  END IF;

  -- 11) دراسة الأسانيد
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='d847df0a-c4fa-4255-b66e-f469546616cb' AND title='أركان دراسة الإسناد: الاتصال والعدالة والضبط') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('أركان دراسة الإسناد: الاتصال والعدالة والضبط', 'أبرز ما يُبحث عنه في دراسة سند الحديث للحكم على درجته', 'd847df0a-c4fa-4255-b66e-f469546616cb', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'أركانها الثلاثة', 'دراسة الإسناد فحص سلسلة الرواة الناقلين للحديث من حيث اتصال السند بسماع كل راوٍ ممن روى عنه، وعدالة الرواة باستقامة دينهم وحفظ مروءتهم، وضبطهم بإتقان الحفظ أو الكتاب، فإذا تحققت هذه الأركان مع سلامة المتن من الشذوذ والعلة القادحة حُكم على الحديث بالصحة أو الحسن، وإن اختل ركن منها حُكم عليه بالضعف بحسب نوع الخلل.', 1),
    (v_lesson, 'evidence', 'أصل التثبت من الخبر', 'قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِنْ جَاءَكُمْ فَاسِقٌ بِنَبَإٍ فَتَبَيَّنُوا﴾ (الحجرات: 6)، وهذه الآية أصل قرآني عام في وجوب التثبت من صدق الناقل للخبر، بنى عليه علماء الحديث منهجهم الدقيق في التحقق من عدالة رواة الإسناد وضبطهم قبل قبول ما رووه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'الكفاية في علم الرواية — الخطيب أبو بكر أحمد بن علي البغدادي', 1);
  END IF;

  -- 12) العلل
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='a5e32413-aeeb-4c69-84da-0c6e0bdf89dd' AND title='تعريف علم علل الحديث وأثره في كشف الخلل الخفي') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف علم علل الحديث وأثره في كشف الخلل الخفي', 'تعريف العلة القادحة الخفية في الحديث وأثر هذا العلم في نقد الروايات', 'a5e32413-aeeb-4c69-84da-0c6e0bdf89dd', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وشرطه', 'علم العلل من أدق علوم الحديث وأشرفها، ويبحث عن أسباب خفية قادحة في صحة الحديث مع ظاهر سلامة سنده، كإرسال خفي في السند أو وهم راوٍ ثقة أو إدراج كلام أحد الرواة في المتن، ولا يقوم بهذا العلم إلا أهل الحفظ والاستقراء الواسع لطرق الحديث لأن كشف العلة يحتاج جمع الطرق كلها والموازنة بينها، لا الاكتفاء بظاهر سند واحد.', 1),
    (v_lesson, 'evidence', 'أصل تمييز الحق من الباطل الملتبس', 'قال تعالى: ﴿وَلَا تَلْبِسُوا الْحَقَّ بِالْبَاطِلِ وَتَكْتُمُوا الْحَقَّ وَأَنْتُمْ تَعْلَمُونَ﴾ (البقرة: 42)، فهذا الأصل في تمييز الحق من الباطل هو ما ينهض به علماء العلل حين يكشفون ما التبس في ظاهر الإسناد الصحيح من علة خفية تُميّز الرواية الصحيحة عن الوهم المندسّ فيها.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'علل الحديث — الإمام ابن أبي حاتم الرازي', 1);
  END IF;

  -- 13) مختلف الحديث ومشكله
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='4457cc33-da81-48c7-9ff3-1c5edc8187fb' AND title='منهج التوفيق بين الأحاديث التي ظاهرها التعارض') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('منهج التوفيق بين الأحاديث التي ظاهرها التعارض', 'تعريف علم مختلف الحديث وطرق العلماء في التوفيق بين النصوص التي ظاهرها التعارض', '4457cc33-da81-48c7-9ff3-1c5edc8187fb', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وطرق التعامل معه', 'مختلف الحديث علم يُعنى بالجمع بين حديثين صحيحين ظاهرهما التعارض، عبر طرق معتبرة كالجمع بحمل كل نص على حال يخصه، أو النسخ إن ثبت تأخر أحدهما، أو الترجيح إن تعذر الجمع والنسخ، وهذا العلم يثبت انتفاء التناقض الحقيقي عن السنة النبوية الصحيحة وأن ما يظهر فيها من تعارض إنما هو تعارض ظاهري يزول بالتأمل الفقهي الدقيق.', 1),
    (v_lesson, 'evidence', 'أصل انتفاء التناقض عن الوحي', 'قال تعالى: ﴿أَفَلَا يَتَدَبَّرُونَ الْقُرْآنَ وَلَوْ كَانَ مِنْ عِنْدِ غَيْرِ اللَّهِ لَوَجَدُوا فِيهِ اخْتِلَافًا كَثِيرًا﴾ (النساء: 82)، وهذا الأصل القرآني في انتفاء التناقض عن الوحي هو ما ينطلق منه علماء مختلف الحديث في تأكيد أن تعارض الأحاديث الصحيحة إنما هو تعارض ظاهري لا حقيقي، يزول بأدوات الجمع أو النسخ أو الترجيح.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'تأويل مختلف الحديث — الإمام عبد الله بن مسلم بن قتيبة الدينوري', 1);
  END IF;

  -- 14) غريب الحديث
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='ec8e4d52-6033-4f34-94bc-0eb08aa5815c' AND title='تعريف علم غريب الحديث وأثره في فهم ألفاظ السنة') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('تعريف علم غريب الحديث وأثره في فهم ألفاظ السنة', 'تعريف علم غريب الحديث وأمثلة عن ألفاظ نبوية يحتاج فهمها إلى شرح لغوي', 'ec8e4d52-6033-4f34-94bc-0eb08aa5815c', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه ونشأته', 'غريب الحديث علم يُعنى ببيان معنى الألفاظ النبوية الغامضة التي قلّ استعمالها في لغة العرب المتأخرة حتى خفي معناها على كثير من الناس، وقد نشأ هذا العلم مبكراً لحاجة الأمة إلى فهم ألفاظ السنة فهماً صحيحاً بعيداً عن دخول العجمة على اللسان العربي بعد اتساع الفتوحات، وأفرد له العلماء مصنفات مستقلة رتبوها على حروف المعجم لتيسير الرجوع إليها.', 1),
    (v_lesson, 'evidence', 'أصل ارتباط الفهم بسلامة اللسان', 'قال تعالى: ﴿إِنَّا أَنْزَلْنَاهُ قُرْآنًا عَرَبِيًّا لَعَلَّكُمْ تَعْقِلُونَ﴾ (يوسف: 2)، وهذا الأصل في ارتباط فهم الوحي بسلامة اللسان العربي ينسحب على فهم السنة أيضاً، فكان لزاماً على العلماء تصنيف كتب غريب الحديث لضبط الألفاظ النبوية التي غمض معناها بعد ابتعاد الناس عن فصيح العربية.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'النهاية في غريب الحديث والأثر — الإمام مجد الدين ابن الأثير الجزري', 1);
  END IF;

  -- 15) فقه الحديث
  IF NOT EXISTS (SELECT 1 FROM lessons WHERE category_id='1c98bbb2-94c9-4766-85bc-e204ed9b0ab0' AND title='الانتقال من رواية الحديث إلى فهم دلالته الفقهية') THEN
    INSERT INTO lessons (title, description, category_id, activity_type, status)
    VALUES ('الانتقال من رواية الحديث إلى فهم دلالته الفقهية', 'تعريف علم فقه الحديث وأثره في استنباط الأحكام من نصوص السنة', '1c98bbb2-94c9-4766-85bc-e204ed9b0ab0', 'درس', 'approved')
    RETURNING id INTO v_lesson;
    INSERT INTO lesson_sections (lesson_id, section_type, title, content, sort_order) VALUES
    (v_lesson, 'terms', 'تعريفه وغايته', 'فقه الحديث هو استخراج الأحكام والفوائد والدلالات من نصوص السنة النبوية بعد التثبت من ثبوتها، ويقوم على جمع طرق الحديث وألفاظه المختلفة، وربطه بنظائره من الآيات والأحاديث، ومعرفة أسباب وروده وملابساته، وهو غاية علوم الحديث كلها لأن رواية الحديث وتصحيحه وسيلة، وفهم دلالته الفقهية والعمل بمقتضاه هو المقصود الأعظم من علم الحديث.', 1),
    (v_lesson, 'evidence', 'الفرق بين نقل الحديث وفقهه', 'عن عبد الله بن مسعود رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: «نَضَّرَ اللَّهُ امْرَأً سَمِعَ مَقَالَتِي فَوَعَاهَا فَأَدَّاهَا كَمَا سَمِعَهَا، فَرُبَّ حَامِلِ فِقْهٍ إِلَى مَنْ هُوَ أَفْقَهُ مِنْهُ» رواه الترمذي وقال: حسن صحيح، وهذا الحديث أصل في التفريق بين مجرد نقل الحديث وبين فقهه، وفيه أن الفقه في الحديث قد يبلغ درجة أعلى عند من ينقل إليه الحديث من درجة الناقل نفسه.', 2);
    INSERT INTO lesson_citations (lesson_id, source_type, citation, sort_order) VALUES
    (v_lesson, 'book', 'سبل السلام الموصلة إلى بلوغ المرام — الإمام محمد بن إسماعيل الصنعاني', 1);
  END IF;

